INSERT INTO "tenant_demo"."remedy_tree_nodes" (id, label, parent_id, description, hindi_label, gujrati_label, punjabi_label, malyalum_label, kannad_label, bengali_label, marathi_label, french_label, german_label, spanish_label, node_type, sort_order) VALUES (117, 'Pain only in lower back?', 116, NULL, 'दर्द केवल पीठ के निचले हिस्से में?', 'ફક્ત નીચલા પીઠમાં પીડા?', 'ਦਰਦ ਸਿਰਫ ਪਿਛਲੇ ਪਾਸੇ ਵਿੱਚ ਹੈ?', 'താഴത്തെ പിന്നിൽ മാത്രം വേദന?', 'ಕಡಿಮೆ ಬೆನ್ನಿನಲ್ಲಿ ಮಾತ್ರ ನೋವು?', 'কেবল নীচের পিছনে ব্যথা?', 'फक्त खालच्या मागे वेदना?', 'Douleur uniquement dans le bas du dos?', 'Schmerzen nur im unteren Rücken?', '¿Dolor solo en la parte baja de la espalda?', 'RUBRIC', 0) ON CONFLICT (id) DO NOTHING;
