INSERT INTO "tenant_demo"."remedy_tree_nodes" (id, label, parent_id, description, hindi_label, gujrati_label, punjabi_label, malyalum_label, kannad_label, bengali_label, marathi_label, french_label, german_label, spanish_label, node_type, sort_order) VALUES (970, 'Hay fever', 0, 'An allergic response causing itchy, watery eyes, sneezing and other similar symptoms. Hay fever, or allergic rhinitis, is a common condition with symptoms similar to those of a cold. There may be sneezing, congestion, runny nose, and sinus pressure.\nIt is caused by an allergic response to airborne substances, such as pollen. The time of year it happens depends on what substance, or allergen, the person reacts to.\nDespite its name, hay fever does not mean that the person is allergic to hay and has a fever. ', 'हे फीवर', 'પરાગરજ તાવ', 'ਘਾਹ ਬੁਖਾਰ', 'ഹേ ഫീവർ', 'ಹೇ ಜ್ವರ', 'খড় জ্বর', 'गवत ताप', 'Rhume des foins', 'Heuschnupfen', 'Fiebre del heno', 'RUBRIC', 0) ON CONFLICT (id) DO NOTHING;
