INSERT INTO "tenant_demo"."remedy_tree_nodes" (id, label, parent_id, description, hindi_label, gujrati_label, punjabi_label, malyalum_label, kannad_label, bengali_label, marathi_label, french_label, german_label, spanish_label, node_type, sort_order) VALUES (inflammation of the voice box) – you may also have a hoarse voice, 'a dry cough and a constant need to clear your throat\r\n•	tonsillitis (inflammation of the tonsils) – you may also have red or spotty tonsils', discomfort when swallowing and a fever\r\n•	strep throat (a bacterial throat infection) – you may also have swollen glands in your neck, 'such as smoke', 'gastro-oesophageal reflux disease (where acid leaks up from the stomach) and allergies.\r\n\r\nWhat are sore throat symptoms?\r\nApart from throat pain', 'sore throat symptoms may include:\r\n•	Fever.\r\n•	Headache.\r\n•	Upset stomach.\r\n•	Swollen lymph nodes.\r\n•	Nasal congestion (stuffy nose).\r\n•	Runny nose.\r\n•	Cough.\r\n•	Fatigue.\r\n•	Hoarseness.\r\n\r\nIs homeopathy effective for sore throat?\r\nHomeopathic remedies are generally considered very safe to use for every age group including children. As homeopathic remedies are mostly made from natural substances', 'therefore', 'they are free from any type of side-effects', 'and they easily treat sore throat.\r\n\r\nWhat are the best homeopathic medicines for sore throat?\r\nThere are several homeopathic medicines which you may find useful for treating throat symptoms. 8 Best medicines for sore throat.\r\n'', ''गला खराब होना'', ''સુકુ ગળું'', ''ਗਲੇ ਵਿੱਚ ਖਰਾਸ਼'', ''തൊണ്ടവേദന'', ''ಗಂಟಲು ಕೆರತ'', ''গলা ব্যথা'', ''घसा घसा'', ''Mal de gorge'', ''Halsentzündung'', ''Dolor de garganta'', NULL, ''2022-11-25 10:37:27'', ''2022-11-25 10:37:27'', NULL', NULL, NULL, NULL, NULL, NULL, 'RUBRIC', 0) ON CONFLICT (id) DO NOTHING;
