INSERT INTO "tenant_demo"."remedy_tree_nodes" (id, label, parent_id, description, hindi_label, gujrati_label, punjabi_label, malyalum_label, kannad_label, bengali_label, marathi_label, french_label, german_label, spanish_label, node_type, sort_order) VALUES (1858, 'Teething', 0, 'Teething is when your baby’s teeth start to come through their gum line. Another word for it is odonatists.\nSome babies are born with their first teeth. Others start teething before they are 4 months old, and some after 12 months. But most babies start teething at around 6 months.', 'बच्चों के दांत निकलना', 'દાંત', 'ਦੰਦ', 'പല്ല്', 'ಹಲ್ಲು', 'দাঁতে দাঁত', 'दात खाणे', 'De façon', 'Zahnen', 'Dentición', 'RUBRIC', 0) ON CONFLICT (id) DO NOTHING;
INSERT INTO "tenant_demo"."remedy_tree_nodes" (id, label, parent_id, description, hindi_label, gujrati_label, punjabi_label, malyalum_label, kannad_label, bengali_label, marathi_label, french_label, german_label, spanish_label, node_type, sort_order) VALUES (1859, 'Travel sickness', 0, 'Motion sickness occurs when your brain can’t make sense of information sent from your eyes, ears and body. Lots of motion- in a car, airplane, boat, or even an amusement park ride can make you feel queasy, clammy or sick to your stomach. Some people vomit.', 'यात्रा संबंधी रोग', 'પ્રવાસ માંદગી', 'ਯਾਤਰਾ ਦੀ ਬਿਮਾਰੀ', 'യാത്ര മൂലമുണ്ടാകുന്ന അസുഖങ്ങൾ', 'ಪ್ರಯಾಣದ ಕಾಯಿಲೆ', 'ভ্রমণ অসুস্থতা', 'प्रवासी आजार', 'Mal des transports', 'Reisekrankheit', 'Enfermedad de viajero', 'RUBRIC', 0) ON CONFLICT (id) DO NOTHING;
INSERT INTO "tenant_demo"."remedy_tree_nodes" (id, label, parent_id, description, hindi_label, gujrati_label, punjabi_label, malyalum_label, kannad_label, bengali_label, marathi_label, french_label, german_label, spanish_label, node_type, sort_order) VALUES (1860, 'Uninary problems - acute', 0, 'A urinary tract infection, commonly known as UTI is one of the most common urinary problems and is an infection that occurs in the urinary tract. This condition can be very painful, and the consequences can get critical if the infection spreads to the kidneys.', 'अनन्य समस्याएं (तीव्र)', 'યુનિનરી સમસ્યાઓ (તીવ્ર)', 'ਗ਼ਲਤ ਸਮੱਸਿਆਵਾਂ (ਗੰਭੀਰ)', 'ഏകീകൃത പ്രശ്നങ്ങൾ (നിശിതം)', 'ಯುಎನ್', 'ইউনিয়ন সমস্যা (তীব্র)', 'अननिन समस्या (तीव्र)', 'Problèmes uninaires (aigu)', 'Unande Probleme (akut)', 'Problemas uninarios (agudos)', 'RUBRIC', 0) ON CONFLICT (id) DO NOTHING;
INSERT INTO "tenant_demo"."remedy_tree_nodes" (id, label, parent_id, description, hindi_label, gujrati_label, punjabi_label, malyalum_label, kannad_label, bengali_label, marathi_label, french_label, german_label, spanish_label, node_type, sort_order) VALUES (1861, 'Warts and verrucae', 0, 'Warts and verrucas are small lumps on the skin that most people have at some point in their life. They usually go away on their own but may take months or even years. Warts are non-cancerous, but can resemble certain cancers.\n\nSometimes only one or two warts develop. Sometimes several occur in the same area of skin.', 'मौसा और वेरुका', 'મસાઓ અને વેર્રુસી', 'ਵਾਰਟਸ ਅਤੇ ਵਰਕਰਾਕੇ', 'അരിമ്പാറയും വെറും വെറും', 'ನರಹುಲಿಗಳು ಮತ್ತು ವರ್ರುಕಾ', 'ওয়ার্টস এবং ভেরুকা', 'Warts आणि verrucae', 'Verrues et verrucae', 'Warzen und Verrucae', 'Verrucas y verrucas', 'RUBRIC', 0) ON CONFLICT (id) DO NOTHING;
INSERT INTO "tenant_demo"."remedy_tree_nodes" (id, label, parent_id, description, hindi_label, gujrati_label, punjabi_label, malyalum_label, kannad_label, bengali_label, marathi_label, french_label, german_label, spanish_label, node_type, sort_order) VALUES (1862, 'Wounds', 0, 'A wound is an injury that breaks the skin or other body tissue. Wounds can be open, with broken skin and exposed body tissue, or closed when there is damage to tissue under intact skin.
