INSERT INTO "tenant_demo"."remedy_tree_nodes" (id, label, parent_id, description, hindi_label, gujrati_label, punjabi_label, malyalum_label, kannad_label, bengali_label, marathi_label, french_label, german_label, spanish_label, node_type, sort_order) VALUES (1987, 'Chilblains', 0, 'Chilblains, also known as pernio, is a medical condition in which damage occurs to capillary beds in the skin, most often in the hands or feet, when blood perfuse into the nearby tissue, resulting in redness, itching, inflammation, and possibly blisters. It occurs most frequently when predisposed individuals, predominantly women, are exposed to cold and humidity. Ulcerated chilblains are referred to as kibes. Temperature-related chilblains can be prevented by keeping the feet and hands warm in cold weather and avoiding exposing these areas to extreme temperature changes. Once the diagnosis of chilblains is made, first-line treatment includes avoiding cold, damp environments and wearing gloves and warm socks.', 'बिवाई', 'ચિલ્ગ્રેન્સ', 'ਚਿਲਬਲੇਨ', 'ചില്ലിലങ്ങൾ', 'ಬೆನ್ನೆಲುನೆ', 'চিলব্লাইনস', 'चिल्बलिन', 'Gisements', 'Chilblains', 'Chilblains', 'RUBRIC', 0) ON CONFLICT (id) DO NOTHING;
